function solve(n, edges) {
    const graph = new Map();
    for (const [u, v, start, end] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ v, start, end });
    }

    const dist = new Array(n).fill(-1);
    dist[0] = 0;

    const pq = new PriorityQueue((a, b) => a.time - b.time);
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node, time } = pq.dequeue();
        if (node === n - 1) break;

        if (dist[node] !== time) continue;

        if (graph.has(node)) {
            for (const { v, start, end } of graph.get(node)) {
                if (time >= start && time <= end) {
                    const newTime = time + 1;
                    if (dist[v] === -1 || newTime < dist[v]) {
                        dist[v] = newTime;
                        pq.enqueue({ node: v, time: newTime });
                    }
                }
            }
        }

        // Option to stay at current node
        if (dist[node] !== -1) {
            const newTime = time + 1;
            if (dist[node] < newTime && dist[node] !== -1) {
                dist[node] = newTime;
                pq.enqueue({ node: node, time: newTime });
            }
        }
    }

    return dist[n - 1] === -1 ? -1 : dist[n - 1];
}

